<?php declare(strict_types=1);use App\Support\View;$action='/admin/people/'.$person->id.'/capacity/overrides/'.$override->id.'/remove';?>
<div class="row justify-content-center"><div class="col-lg-7"><h1 class="h2">Remove capacity override</h1><div class="card card-body"><dl class="row"><dt class="col-sm-5">Person</dt><dd class="col-sm-7"><?= View::escape($person->fullName()) ?></dd><dt class="col-sm-5">Month</dt><dd class="col-sm-7"><?= View::escape($override->monthLabel()) ?></dd><dt class="col-sm-5">Override</dt><dd class="col-sm-7"><?= View::escape($override->availableHours) ?></dd><dt class="col-sm-5">Resulting standard capacity</dt><dd class="col-sm-7"><?= View::escape($person->defaultMonthlyCapacityHours) ?></dd><dt class="col-sm-5">Current planned / actual</dt><dd class="col-sm-7"><?= View::escape($summary->plannedHours) ?> / <?= View::escape($summary->actualHours) ?></dd></dl><?php if($decimals->compare($summary->plannedHours,$person->defaultMonthlyCapacityHours)>0):?><div class="alert alert-warning">Removing this override will leave planned hours over standard capacity.</div><?php endif;?><form method="post" action="<?= View::escape($urls->to($action)) ?>"><input type="hidden" name="_csrf" value="<?= View::escape($csrfToken) ?>"><button class="btn btn-danger">Confirm removal</button> <a class="btn btn-outline-secondary" href="<?= View::escape($urls->to('/people/'.$person->id.'/capacity',['year'=>$override->year])) ?>">Cancel</a></form></div></div></div>
